```java
boolean isAnagram(String a, String b) {
  if (a == null || b == null) return false;
  char[] ca = a.toLowerCase().replaceAll('\\s', '').toCharArray();
  char[] cb = b.toLowerCase().replaceAll('\\s', '').toCharArray();
  Arrays.sort(ca); Arrays.sort(cb);
  return Arrays.equals(ca, cb);
}

// Test
@Test void anagramTest() {
  assertTrue(isAnagram('listen', 'silent'));
  assertTrue(isAnagram('Astronomer', 'Moon starer'));
  assertFalse(isAnagram('hello', 'world'));
  assertFalse(isAnagram(null, 'test'));
  assertTrue(isAnagram('', ''));
}
```
